// Extract the text response from Gemini and parse it as JSON
const geminiResponse = $input.first().json;

// Navigate Gemini's response structure
let text = '';
try {
  text = geminiResponse.candidates[0].content.parts[0].text;
} catch (e) {
  return [{ json: {
    plan: 'Error: Could not parse Gemini response',
    requires_confirmation: false,
    steps: []
  }}];
}

// Clean up: remove markdown code fences if present
text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

// Parse the JSON
try {
  const parsed = JSON.parse(text);

  // Validate structure
  const result = {
    plan: parsed.plan || 'Executing command...',
    requires_confirmation: parsed.requires_confirmation || false,
    steps: Array.isArray(parsed.steps) ? parsed.steps : []
  };

  return [{ json: result }];
} catch (e) {
  return [{ json: {
    plan: `Error parsing LLM output: ${text.substring(0, 200)}`,
    requires_confirmation: false,
    steps: []
  }}];
}
